def test_payroll_run_atomic_rollback_on_internal_failure(
    hr_admin_client,
    payroll_period,
    fault_injection_headers,  # <fixture> returns {"X-Fault-Inject": "payroll-compute"}
    api_base,
):
    payload = {**payroll_period, "_test_force_period": "FAULT-TEST"}
    resp = hr_admin_client.post(
        f"{api_base}/api/payroll-runs",
        json=payload,
        headers=fault_injection_headers,
    )
    assert resp.status_code == 500, resp.text
    run_id = resp.json().get("run_id") or "FAULT-TEST"

    stubs_resp = hr_admin_client.get(
        f"{api_base}/api/pay-stubs", params={"run_id": run_id}
    )
    items = stubs_resp.json().get("items", [])
    assert items == [], f"Partial stubs committed: {items}"

    run_resp = hr_admin_client.get(f"{api_base}/api/payroll-runs/{run_id}")
    if run_resp.status_code == 200:
        assert run_resp.json()["state"] in ("rolled_back", "failed")
    else:
        assert run_resp.status_code == 404

import time

def test_payroll_run_state_transitions_idle_to_completed(
    hr_admin_client,
    payroll_period,
    unique_period,  # <fixture> returns a period string not yet used
    api_base,
):
    list_resp = hr_admin_client.get(
        f"{api_base}/api/payroll-runs", params={"period": unique_period}
    )
    existing = list_resp.json().get("items", [])
    assert existing == [], "Pre-condition failed: run already exists"

    payload = {"period": unique_period}
    post_resp = hr_admin_client.post(f"{api_base}/api/payroll-runs", json=payload)
    assert post_resp.status_code in (200, 201, 202), post_resp.text
    run_id = post_resp.json()["run_id"]

    terminal_states = {"completed", "failed", "rolled_back"}
    state = None
    for _ in range(10):
        run = hr_admin_client.get(f"{api_base}/api/payroll-runs/{run_id}").json()
        state = run["state"]
        if state in terminal_states:
            break
        time.sleep(1)

    assert state == "completed", f"Unexpected terminal state: {state}"
